import React from 'react';

const MissionList = () => {
    return (
       <div
      className={`p-2 m-2 border rounded cursor-pointer transition ${
        task.completed ? "bg-green-200 line-through" : "bg-white"
      }`}
      onClick={() => toggleTask(task.id)}
    >
      {task.text}
    </div>
    );
};
export default MissionList;
